/**
 * Copied from ZionCMS package slightly modified for RootsTech Promo use
 */
import React, { useMemo, createContext } from 'react'
import { ApolloClient, InMemoryCache, ApolloProvider, type DocumentNode } from '@apollo/client'
import { i18n } from '@fs/zion-locale'
import { appConfig } from '@fs/zion-config'
import { getSessionId } from '@fs/zion-session'
import { useFeatureFlag } from '@fs/zion-flags'

import ApolloMultiLink from './ApolloMultiLink'

const hasProcess = typeof process !== 'undefined'

const { BRIGHTSPOT_API_KEY, BRIGHTSPOT_URL } = appConfig
const ENV_BRIGHTSPOT_API_KEY = hasProcess && process.env.FS_CLIENT_APP_BRIGHTSPOT_API_KEY
const ENV_BRIGHTSPOT_URL = hasProcess && process.env.FS_CLIENT_APP_BRIGHTSPOT_URL

export type ContentTypeMap = {
  contentType: string
  renderFunction: ({
    resolvedSite,
    relativeUrl,
    contentType,
    previewId,
  }: {
    resolvedSite: string | null | undefined
    relativeUrl: string | null | undefined
    contentType: string | null | undefined
    previewId: string | null | undefined
  }) => JSX.Element
}

type BrightspotContext = {
  customPageQuery?: DocumentNode
  /**
   * A list of Brightspot sites the BrightspotProvider will be configured to use.
   */
  sites: string[]
  /**
   * List of sites that support subsites.
   */
  subsites: string[]

  /**
   * A map of custom content types to their respective queries.
   */
  customContentTypes: ContentTypeMap[]
}

/**
 * React context for Brightspot CMS configuration
 *
 * Provides Brightspot site configuration, custom content types, and subsites
 * to child components through React context.
 */
export const BrightspotContext = createContext<BrightspotContext>({} as BrightspotContext)

type BrightspotProviderProps = {
  /**
   * A list of Brightspot sites for the BrightspotProvider to use.
   */
  sites: string[]
  /**
   * True if the sites need custom content support. If so then '<site>:custom' context will be supported to access the
   * custom content GraphQL.
   */
  hasCustomContent?: boolean
  /**
   * List of sites that support subsites.
   */
  subsites?: string[]

  /**
   * A map of custom content types to their respective queries.
   */
  customContentTypes?: ContentTypeMap[]

  children: React.ReactNode
}

/**
 * BrightspotProvider - Apollo Client provider for Brightspot CMS
 *
 * Creates and configures an Apollo Client for accessing Brightspot CMS GraphQL endpoints.
 * Supports multiple sites, custom content types, subsites, and ECT proxy routing.
 *
 * Features:
 * - Configures multiple GraphQL endpoints per site (delivery, location-event-calendar, help-center, marketing, custom)
 * - Automatically includes authentication headers (session ID, API key, locale)
 * - Supports ECT proxy routing via feature flag
 * - Provides Brightspot context to child components
 *
 * @param {BrightspotProviderProps} props - Provider configuration
 * @param {string[]} props.sites - List of Brightspot site identifiers to configure
 * @param {boolean} [props.hasCustomContent=false] - Enable custom content GraphQL endpoint
 * @param {string[]} [props.subsites=[]] - List of sites that support subsites
 * @param {ContentTypeMap[]} [props.customContentTypes=[]] - Custom content type mappings
 * @param {React.ReactNode} props.children - Child components to wrap with provider
 * @returns {JSX.Element} ApolloProvider with BrightspotContext
 */
export default function BrightspotProvider({
  sites,
  hasCustomContent = false,
  subsites = [],
  customContentTypes = [],
  children,
}: BrightspotProviderProps): JSX.Element {
  const useEctProxy = useFeatureFlag('ZionCMS_UseEctProxy') || { isOn: false }
  const endpoints = sites.reduce((acc, site) => {
    const baseUrl = BRIGHTSPOT_URL || ENV_BRIGHTSPOT_URL
    acc[site] = `${baseUrl}${site}/graphql/delivery/zion-cms`
    acc[`${site}:loc-evt-cal`] = `${baseUrl}${site}/graphql/delivery/location-event-calendar`
    acc[`${site}:help-ctr`] = `${baseUrl}${site}/graphql/delivery/help-center`
    acc[`${site}:marketing`] = `${baseUrl}${site}/graphql/delivery/marketing`
    if (hasCustomContent) {
      acc[`${site}:custom`] = `${baseUrl}${site}/graphql/delivery/custom-type-graphql`
    }
    return acc
  }, {})

  const client = useMemo(() => {
    const link = new ApolloMultiLink({
      baseUrl: BRIGHTSPOT_URL || ENV_BRIGHTSPOT_URL,
      endpoints,
      useEctProxy: useEctProxy.isOn,
      subsites: subsites || [],
      getContext: () => ({
        headers: {
          'Accept-Language': i18n.language === 'zh-hans' ? 'zh-CN' : i18n.language,
          fssessionid: getSessionId() || '',
          'x-api-key': BRIGHTSPOT_API_KEY || ENV_BRIGHTSPOT_API_KEY,
        },
      }),
    })
    return new ApolloClient({
      link,
      cache: new InMemoryCache(),
      devtools: {
        enabled: process.env.NODE_ENV === 'development',
      },
    })
  }, [endpoints, subsites, useEctProxy.isOn])

  const contextValue = useMemo(() => ({ sites, subsites, customContentTypes }), [sites, subsites, customContentTypes])

  return (
    <ApolloProvider client={client}>
      <BrightspotContext.Provider value={contextValue}>{children}</BrightspotContext.Provider>
    </ApolloProvider>
  )
}
